16	
17	// Native functions defined in jtag_socket.cpp
18	import "DPI-C" function int open_jtag_socket(input int port);
19	import "DPI-C" function int poll_jtag_request(output bit[31:0] instructionLength,
20	    output bit[31:0] instruction, output bit[31:0] dataLength, output bit[63:0] data);
21	import "DPI-C" function void send_jtag_response(input bit[31:0] instruction, input bit[63:0] data);
22	
23	//
24	// This simulates a JTAG host. It proxies messages from an external test program
25	// over a socket. It uses DPI to call into native code (jtag_socket.cpp) that polls
26	// the socket for new messages.
27	//
28	
29	module sim_jtag
30	    (input                     clk,
31	    jtag_interface.host        jtag);
32	
33	    typedef enum int {
34	        JTAG_RESET,
35	        JTAG_IDLE,
36	        JTAG_SELECT_DR_SCAN,
37	        JTAG_CAPTURE_DR,
38	        JTAG_SHIFT_DR,
39	        JTAG_EXIT1_DR,
40	        JTAG_PAUSE_DR,
41	        JTAG_EXIT2_DR,
42	        JTAG_UPDATE_DR,
43	        JTAG_SELECT_IR_SCAN,
44	        JTAG_CAPTURE_IR,
45	        JTAG_SHIFT_IR,
46	        JTAG_EXIT1_IR,
47	        JTAG_PAUSE_IR,
48	        JTAG_EXIT2_IR,
49	        JTAG_UPDATE_IR
50	    } jtag_state_t;
51	
52	    localparam MAX_DATA_LEN = 64;
53	    localparam MAX_INSTRUCTION_LEN = 32;
54	    localparam CLOCK_DIVISOR = 7;
55	
56	    int control_port_open;
57	    bit[31:0] instruction_length;
58	    bit[MAX_INSTRUCTION_LEN - 1:0] instruction;
59	    bit[31:0] data_length;
60	    bit[MAX_DATA_LEN - 1:0] data;
61	    bit[MAX_INSTRUCTION_LEN - 1:0] instruction_shift;
62	    bit[MAX_DATA_LEN - 1:0] data_shift;
63	    int shift_count;
64	    jtag_state_t state_ff = JTAG_RESET;
65	    jtag_state_t state_nxt;
66	    int divider_count;
67	    logic tms_nxt;
68	    logic need_ir_shift;
69	    logic need_dr_shift;
70	    logic need_reset;
71	
72	    initial
73	    begin
74	        int jtag_port;
75	        if ($value$plusargs("jtag_port=%d", jtag_port) != 0)
76	            control_port_open = open_jtag_socket(jtag_port);
77	        else
78	            control_port_open = 0;
79	
80	        state_ff = JTAG_RESET;
81	        data_shift = '0;
82	        instruction_shift = '0;
83	        need_dr_shift = '0;
84	        need_ir_shift = '0;
85	        need_reset = '0;
86	        shift_count = '0;
87	        divider_count = 0;
88	    end
89	
90	    always @(posedge clk)
91	    begin
92	        if (divider_count == 0)
93	        begin
94	            jtag.tck <= !jtag.tck;
95	            divider_count <= CLOCK_DIVISOR;
96	        end
97	        else
98	            divider_count <= divider_count - 1;
99	    end
100	
101	    // Set up outgoing signals on falling edge
102	    always @(negedge jtag.tck)
103	    begin
104	        if (state_ff == JTAG_SHIFT_DR)
105	            jtag.tdo <= data_shift[0];
106	        else
107	            jtag.tdo <= instruction_shift[0];
108	
109	        jtag.tms <= tms_nxt;
110	    end
111	
112	    always @(posedge jtag.tck)
113	    begin
114	        if (control_port_open != 0 && !need_ir_shift && !need_dr_shift && !need_reset)
115	        begin
116	            // Check if we have a new messsage request in the socket
117	            // from the test harness
118	            if (poll_jtag_request(instruction_length, instruction,
119	                data_length, data) != 0)
120	            begin
121	                // Ensure test harness doesn't send bad lengths (these are unsigned)
122	                assert(instruction_length <= 32);
123	                assert(data_length <= MAX_DATA_LEN);
124	
125	                // Specifying a zero length will cause the corresponding register
126	                // not to be shifted.
127	                if (instruction_length != 0)
128	                    need_ir_shift <= 1;
129	
130	                if (data_length != 0)
131	                    need_dr_shift <= 1;
132	
133	                if (instruction_length == 0 && data_length == 0)
134	                    need_reset <= 1;
135	            end
136	        end
137	
138	        // Should not have need_reset set if there is a rest to send an IR
139	        // or DR register.
140	        assert(!need_reset || !(need_ir_shift || need_dr_shift));
141	
142	        state_ff <= state_nxt;
143	        case (state_ff)
144	            JTAG_SELECT_DR_SCAN:
145	            begin
146	                // Should not enter this state unless we have something to do.
147	                assert(need_ir_shift || need_dr_shift || need_reset);
148	            end
149	
150	            JTAG_CAPTURE_DR:
151	            begin
152	                shift_count <= data_length;
153	                data_shift <= data;
154	            end
155	
156	            JTAG_SHIFT_DR:
157	            begin
158	                data_shift <= (data_shift >> 1) | (MAX_DATA_LEN'(jtag.tdi)
159	                    << (data_length - 1));
160	                shift_count <= shift_count - 1;
161	                assert(need_dr_shift);
162	                assert(shift_count > 0);
163	            end
164	
165	            JTAG_UPDATE_DR:
166	            begin
167	                assert(shift_count == 0);
168	                send_jtag_response(instruction_shift, data_shift);
169	                need_dr_shift <= 0;
170	            end
171	
172	            JTAG_SELECT_IR_SCAN:
173	            begin
174	                // Shouldn't get to this state unless we are about
175	                // to shift in a new IR or going to reset state.
176	                assert(need_ir_shift || need_reset);
177	                assert(!(need_ir_shift && need_reset));
178	
179	                if (need_reset)
180	                begin
181	                    need_reset <= 0;
182	                    send_jtag_response(0, 0);
183	                end
184	            end
185	
186	            JTAG_CAPTURE_IR:
187	            begin
188	                shift_count <= instruction_length;
189	                instruction_shift <= instruction;
190	            end
191	
192	            JTAG_SHIFT_IR:
193	            begin
194	                instruction_shift <= (instruction_shift >> 1)
195	                    | (MAX_INSTRUCTION_LEN'(jtag.tdi)
196	                    << (instruction_length - 1));
197	                shift_count <= shift_count - 1;
198	                assert(need_ir_shift);
199	                assert(shift_count > 0);
200	            end
201	
202	            JTAG_UPDATE_IR:
203	            begin
204	                assert(shift_count == 0);
205	                need_ir_shift <= 0;
206	                if (!need_dr_shift)
207	                begin
208	                    // There was an instruction, but no data
209	                    send_jtag_response(instruction_shift, 0);
210	                end
211	            end
212	        endcase
213	    end
214	
215	    // The FSM is structured so it will always make progress if this returns 0.
216	    function random_transition();
217	        random_transition = ($random() & 1) == 0;
218	    endfunction
219	
220	    always_comb
221	    begin
222	        state_nxt = state_ff;
223	        jtag.trst_n = 1;
224	        case (state_ff)
225	            JTAG_RESET:
226	            begin
227	                jtag.trst_n = 0;
228	                state_nxt = JTAG_IDLE;
229	                tms_nxt = 0;  // Go to idle state
230	            end
231	
232	            JTAG_IDLE:
233	            begin
234	                // We may be here because already shifted the IR and
235	                // randomly returned to idle, or because we haven't shifted
236	                // the IR yet.
237	                if (need_ir_shift || need_dr_shift || need_reset)
238	                begin
239	                    state_nxt = JTAG_SELECT_DR_SCAN;
240	                    tms_nxt = 1;
241	                end
242	                else
243	                    tms_nxt = 0;
244	            end
245	
246	            JTAG_SELECT_DR_SCAN:
247	            begin
248	                if (need_ir_shift || need_reset)
249	                begin
250	                    // Have to shift IR first
251	                    state_nxt = JTAG_SELECT_IR_SCAN;
252	                    tms_nxt = 1;
253	                end
254	                else
255	                begin
256	                    state_nxt = JTAG_CAPTURE_DR;
257	                    tms_nxt = 0;
258	                end
259	            end
260	
261	            JTAG_CAPTURE_DR:
262	            begin
263	                if (random_transition())
264	                begin
265	                    tms_nxt = 1;
266	                    state_nxt = JTAG_EXIT1_DR;
267	                end
268	                else
269	                begin
270	                    tms_nxt = 0;
271	                    state_nxt = JTAG_SHIFT_DR;
272	                end
273	            end
274	
275	            JTAG_SHIFT_DR:
276	            begin
277	                if (shift_count == 1 || random_transition())
278	                begin
279	                    tms_nxt = 1;
280	                    state_nxt = JTAG_EXIT1_DR;
281	                end
282	                else
283	                    tms_nxt = 0;
284	            end
285	
286	            JTAG_EXIT1_DR:
287	            begin
288	                if (shift_count == 0 && !random_transition())
289	                begin
290	                    tms_nxt = 1;
291	                    state_nxt = JTAG_UPDATE_DR;
292	                end
293	                else
294	                begin
295	                    tms_nxt = 0;
296	                    state_nxt = JTAG_PAUSE_DR;
297	                end
298	            end
299	
300	            JTAG_PAUSE_DR:
301	            begin
302	                if (random_transition())
303	                    tms_nxt = 0;
304	                else
305	                begin
306	                    tms_nxt = 1;
307	                    state_nxt = JTAG_EXIT2_DR;
308	                end
309	            end
310	
311	            JTAG_EXIT2_DR:
312	            begin
313	                if (shift_count != 0)
314	                begin
315	                    tms_nxt = 0;
316	                    state_nxt = JTAG_SHIFT_DR;
317	                end
318	                else
319	                begin
320	                    tms_nxt = 1;
321	                    state_nxt = JTAG_UPDATE_DR;
322	                end
323	            end
324	
325	            JTAG_UPDATE_DR:
326	            begin
327	                // XXX Since we always shift DR last and won't check for a new
328	                // message until back in idle, we always have to go back to idle.
329	                // This does not exercise the transition back to DR_SCAN.
